import SwiftUI

struct WaveformView: View {
    @State private var samples: [CGFloat] = Array(repeating: 0, count: 128)
    var body: some View {
        Canvas { context, size in
            let path = Path { p in
                p.move(to: .zero)
                for (i, sample) in samples.enumerated() {
                    let x = size.width * CGFloat(i) / CGFloat(samples.count - 1)
                    let y = size.height/2 - sample * size.height/2
                    p.addLine(to: CGPoint(x: x, y: y))
                }
            }
            context.stroke(path, with: .color(.blue), lineWidth: 2)
        }
        .onReceive(waveformPublisher) { newSamples in
            samples = newSamples
        }
        .performanceSensitive()
    }
    // Simulated waveform data publisher
    var waveformPublisher: some Publisher<[CGFloat], Never> {
        Timer.publish(every: 1.0/60.0, on: .main, in: .common)
            .autoconnect()
            .map { _ in (0..<128).map { _ in .random(in: -1...1) } }
    }
}

import SwiftUI

struct ParticleField: View {
    @State private var particles: [CGPoint] = (0..<500).map { _ in CGPoint(x: .random(in: 0...400), y: .random(in: 0...800)) }
    var body: some View {
        TimelineView(.animation) { context in
            Canvas { ctx, size in
                for p in particles {
                    ctx.fill(Path(ellipseIn: CGRect(origin: p, size: CGSize(width: 4, height: 4))), with: .color(.white))
                }
            }
            .performanceSensitive()
            .onChange(of: context.date) { _ in
                withAnimation(.linear(duration: 1.0/60.0)) {
                    particles = particles.map { CGPoint(x: $0.x + .random(in: -1...1), y: $0.y + .random(in: -1...1)) }
                }
            }
        }
    }
}

