import SwiftUI

struct AdaptivePerformanceModifier: ViewModifier {
    @State private var lastUpdate: Date = .now
    @State private var updateCount: Int = 0
    @State private var isSensitive: Bool = false
    let threshold: Int
    func body(content: Content) -> some View {
        content
            .onAppear { lastUpdate = .now }
            .onChange(of: Date()) { _ in
                updateCount += 1
                if Date().timeIntervalSince(lastUpdate) > 1 {
                    isSensitive = updateCount > threshold
                    updateCount = 0
                    lastUpdate = .now
                }
            }
            .modifier(isSensitive ? PerformanceSensitive() : IdentityModifier())
    }
}

struct PerformanceSensitive: ViewModifier {
    func body(content: Content) -> some View {
        content.performanceSensitive()
    }
}
struct IdentityModifier: ViewModifier {
    func body(content: Content) -> some View { content }
}

import SwiftUI

struct BigDataChart: View {
    let data = (0..<10_000).map { sin(Double($0)/100) }
    var body: some View {
        ScrollView(.horizontal) {
            Canvas { context, size in
                var path = Path()
                for (i, y) in data.enumerated() {
                    let x = size.width * CGFloat(i) / CGFloat(data.count - 1)
                    let yPos = size.height/2 - CGFloat(y) * size.height/2
                    if i == 0 { path.move(to: CGPoint(x: x, y: yPos)) }
                    else { path.addLine(to: CGPoint(x: x, y: yPos)) }
                }
                context.stroke(path, with: .color(.red), lineWidth: 1)
            }
            .frame(width: 2000, height: 200)
            .performanceSensitive()
        }
    }
}
